import { Resend } from 'resend';
import { createClient } from '@supabase/supabase-js';
import type { VercelRequest, VercelResponse } from '@vercel/node';
import fs from 'fs';
import path from 'path';

// Logo embedded as Base64 to avoid Vercel filesystem/auth issues
const LOGO_BASE64 = '';

const COLORS = {
    bg: '#f8f9fa',
    primary: '#3a572c',
    text: '#1f2937',
    secondary: '#4b5563',
    white: '#ffffff'
};

// Hardened BASE_URL detection
const getBaseUrl = (req: VercelRequest) => {
    // 1. Check x-forwarded-host (most reliable on Vercel)
    const host = req.headers['x-forwarded-host'] || req.headers.host || '';
    const protocol = req.headers['x-forwarded-proto'] || 'https';

    // 2. Explicit mapping for our environments to avoid any ambiguity
    if (host.includes('test.drinkboostup.cz')) {
        return 'https://test.drinkboostup.cz';
    }
    if (host.includes('drinkboostup.cz') && !host.includes('test.')) {
        return 'https://drinkboostup.cz';
    }

    // 3. Detected host from headers (if not our main domains)
    if (host && !host.includes('localhost') && !host.includes('127.0.0.1')) {
        return `${protocol}://${host}`.replace(/\/$/, "");
    }

    // 4. Explicit site URL from environment
    if (process.env.VITE_SITE_URL && !process.env.VITE_SITE_URL.includes('localhost')) {
        return process.env.VITE_SITE_URL.replace(/\/$/, "");
    }

    // 5. Fallback for localhost development
    if (host.includes('localhost') || host.includes('127.0.0.1')) {
        return `${protocol}://${host}`.replace(/\/$/, "");
    }

    // 6. Final fallback
    return 'https://drinkboostup.cz';
};

// Initialize Supabase Admin
const supabaseAdmin = createClient(
    process.env.VITE_SUPABASE_URL || '',
    process.env.SUPABASE_SERVICE_ROLE_KEY || '',
    {
        auth: {
            autoRefreshToken: false,
            persistSession: false
        }
    }
);

export default async function handler(req: VercelRequest, res: VercelResponse) {
    if (req.method !== 'POST') {
        return res.status(405).json({ error: 'Method not allowed' });
    }

    const BASE_URL = getBaseUrl(req);
    const apiKey = process.env.RESEND_API_KEY;
    if (!apiKey) {
        console.error('RESEND_API_KEY not set');
        return res.status(500).json({ error: 'Email service not configured' });
    }

    const resend = new Resend(apiKey);

    const {
        to,
        type = 'order_confirmation',
        customerName = 'zákazníku',
        orderNumber,
        items = [],
        total,
        trackingNumber,
        message, // For contact auto-reply
    } = req.body;

    if (!to) {
        return res.status(400).json({ error: 'Missing recipient email' });
    }

    let subject = 'BoostUp';
    let contentHtml = '';
    let heroImageUrl = '';
    let heroCid = '';

    switch (type) {
        case 'confirm_signup': {
            subject = 'Potvrď svůj e-mail | BoostUp ⚡';
            let confirmationLink = req.body.confirmationLink;

            if (!confirmationLink && to) {
                try {
                    const { data: linkData, error: linkError } = await supabaseAdmin.auth.admin.generateLink({
                        type: 'signup',
                        email: to,
                        options: { redirectTo: `${BASE_URL}/login` }
                    });
                    if (linkError) {
                        console.error('Supabase generateLink error (signup):', linkError);
                        throw linkError;
                    }
                    confirmationLink = linkData.properties.action_link;
                } catch (err: any) {
                    console.error('Failed to generate signup link:', err);
                    return res.status(500).json({ 
                        error: 'Failed to generate signup link',
                        details: process.env.NODE_ENV === 'development' ? err.message : undefined
                    });
                }
            }

            contentHtml = `
                <h2 style="color:${COLORS.primary};margin:0 0 16px 0;font-size:24px;font-weight:bold">Vítej v týmu! 🚀 Prověříme se?</h2>
                <p style="margin:0 0 24px 0;font-size:16px;color:${COLORS.secondary}">Děkujeme za registraci na BoostUp Energy. Pro aktivaci tvého účtu prosím klikni na tlačítko níže.</p>
                <div style="margin:32px 0;text-align:center">
                    <a href="${confirmationLink}" style="background:${COLORS.primary};color:white;padding:16px 32px;border-radius:12px;text-decoration:none;font-weight:bold;display:inline-block;font-size:16px">Potvrdit e-mail</a>
                </div>
                <p style="margin:32px 0 0 0;font-size:13px;color:${COLORS.secondary}">Pokud jsi se neregistroval, můžeš tento e-mail bezpečně ignorovat.</p>
            `;
            break;
        }

        case 'reset_password': {
            subject = 'Obnova hesla | BoostUp ⚡';
            let resetLink = req.body.resetLink;

            if (!resetLink && to) {
                try {
                    const { data: linkData, error: linkError } = await supabaseAdmin.auth.admin.generateLink({
                        type: 'recovery',
                        email: to,
                        options: { redirectTo: `${BASE_URL}/reset-password` }
                    });
                    
                    if (linkError) {
                        console.error('Supabase generateLink error (recovery):', linkError);
                        // If linkError is specifically "User not found", we might want to mask it or handle it
                        throw linkError;
                    }
                    resetLink = linkData.properties.action_link;
                } catch (err: any) {
                    console.error('Failed to generate reset link:', err);
                    return res.status(500).json({ 
                        error: 'Failed to generate reset link',
                        details: process.env.NODE_ENV === 'development' ? err.message : undefined 
                    });
                }
            }

            contentHtml = `
                <h2 style="color:${COLORS.primary};margin:0 0 16px 0;font-size:24px;font-weight:bold">Zapomenuté heslo?</h2>
                <p style="margin:0 0 24px 0;font-size:16px;color:${COLORS.secondary}">To se stane každému. Klikni na tlačítko níže a nastav si nové heslo ke svému účtu.</p>
                <div style="margin:32px 0;text-align:center">
                    <a href="${resetLink}" style="background:${COLORS.primary};color:white;padding:16px 32px;border-radius:12px;text-decoration:none;font-weight:bold;display:inline-block;font-size:16px">Změnit heslo</a>
                </div>
                <p style="margin:32px 0 0 0;font-size:13px;color:${COLORS.secondary}">Tento odkaz vyprší za 24 hodin. Pokud jsi o změnu nežádal, nic se neděje – tvoje heslo zůstane nezměněno.</p>
            `;
            break;
        }

        case 'magic_link': {
            subject = 'Přihlášení do BoostUp ⚡';
            let magicLink = req.body.magicLink;

            if (!magicLink && to) {
                try {
                    const { data: linkData, error: linkError } = await supabaseAdmin.auth.admin.generateLink({
                        type: 'magiclink',
                        email: to,
                        options: { redirectTo: BASE_URL }
                    });
                    if (linkError) {
                        console.error('Supabase generateLink error (magiclink):', linkError);
                        throw linkError;
                    }
                    magicLink = linkData.properties.action_link;
                } catch (err: any) {
                    console.error('Failed to generate magic link:', err);
                    return res.status(500).json({ 
                        error: 'Failed to generate magic link',
                        details: process.env.NODE_ENV === 'development' ? err.message : undefined
                    });
                }
            }

            contentHtml = `
                <h2 style="color:${COLORS.primary};margin:0 0 16px 0;font-size:24px;font-weight:bold">Tvůj odkaz pro přihlášení</h2>
                <p style="margin:0 0 32px 0;font-size:16px;color:${COLORS.secondary}">Kliknutím na tlačítko níže budeš okamžitě přihlášen ke svému účtu.</p>
                <div style="margin:32px 0;text-align:center">
                    <a href="${magicLink}" style="background:${COLORS.primary};color:white;padding:16px 32px;border-radius:12px;text-decoration:none;font-weight:bold;display:inline-block;font-size:16px">Přihlásit se</a>
                </div>
                <p style="margin:32px 0 0 0;font-size:13px;color:${COLORS.secondary}">Tento odkaz je platný pouze po omezenou dobu. Pokud jsi jsi ho nevyžádal, můžeš tento e-mail ignorovat.</p>
            `;
            break;
        }

        case 'registration':
            subject = 'Vítej v týmu BoostUp! 🚀';
            heroImageUrl = `${BASE_URL}/email-welcome.png?v=3`;
            heroCid = 'welcome';
            contentHtml = `
                <h1 style="color:${COLORS.primary};margin:0 0 16px 0;font-size:28px;font-weight:bold">Ahoj ${customerName}!</h1>
                <p style="margin:0 0 24px 0;font-size:16px;color:${COLORS.secondary}">Jsme nadšení, že ses přidal k BoostUp. Tvůj účet byl úspěšně vytvořen a teď už ti nic nebrání v cestě za maximálním výkonem.</p>
                <div style="margin:30px 0;text-align:center">
                    <a href="${BASE_URL}" style="background:${COLORS.primary};color:white;padding:16px 32px;border-radius:12px;text-decoration:none;font-weight:bold;display:inline-block;font-size:16px">Doplnit zásoby energie</a>
                </div>
                <p style="margin:0;font-size:14px;color:${COLORS.secondary}">Pokud budeš cokoliv potřebovat, stačí odpovědět na tento e-mail.</p>
            `;
            break;

        case 'order_confirmation': {
            subject = `✅ Potvrzení objednávky ${orderNumber} | BoostUp`;
            const itemsHtml = items.map((i: any) => {
                let details = '';
                let displayName = i.name;

                if (i.mixConfiguration) {
                    const flavors = [];
                    let totalBottles = 0;
                    if (i.mixConfiguration.lemon) {
                        flavors.push(`Lemon: ${i.mixConfiguration.lemon} ks`);
                        totalBottles += i.mixConfiguration.lemon;
                    }
                    if (i.mixConfiguration.red) {
                        flavors.push(`Red: ${i.mixConfiguration.red} ks`);
                        totalBottles += i.mixConfiguration.red;
                    }
                    if (i.mixConfiguration.silky) {
                        flavors.push(`Silky: ${i.mixConfiguration.silky} ks`);
                        totalBottles += i.mixConfiguration.silky;
                    }
                    details = `<div style="font-size:12px;color:${COLORS.secondary};margin-top:4px">— ${flavors.join(', ')} (${totalBottles} ks celkem)</div>`;
                    displayName = displayName.replace('(MIX)', `(MIX-${totalBottles})`);
                }
                return `<tr><td style="padding:12px 0;border-bottom:1px solid #f3f4f6"><div style="font-weight:500">${displayName} × ${i.quantity}</div>${details}</td><td style="padding:12px 0;text-align:right;border-bottom:1px solid #f3f4f6;vertical-align:top;font-weight:600">${(i.price * i.quantity).toFixed(0)} Kč</td></tr>`;
            }).join('');

            contentHtml = `
                <h2 style="color:${COLORS.primary};margin:0 0 16px 0;font-size:24px;font-weight:bold">Díky za tvoji objednávku!</h2>
                <p style="margin:0 0 24px 0;font-size:16px;color:${COLORS.secondary}">Ahoj ${customerName}, tvoje objednávka <strong>${orderNumber}</strong> byla úspěšně přijata. Už na ní začínáme pracovat.</p>
                <table style="width:100%;margin:24px 0;border-collapse:collapse;text-align:left">
                    ${itemsHtml}
                    <tr>
                        <td style="padding:20px 0 0 0;font-size:18px;font-weight:bold;color:${COLORS.text}">Celkem</td>
                        <td style="padding:20px 0 0 0;text-align:right;font-size:22px;font-weight:bold;color:${COLORS.primary}">${Number(total).toFixed(0)} Kč</td>
                    </tr>
                </table>
                <p style="margin:0;font-size:14px;color:${COLORS.secondary}">Hned jak zásilku předáme dopravci, pošleme ti e-mail se sledovacím číslem.</p>
            `;
            break;
        }

        case 'shipping': {
            subject = `🚚 Tvoje zásilka ${orderNumber} je na cestě! | BoostUp`;
            heroImageUrl = `${BASE_URL}/email-shipping.png?v=3`;
            heroCid = 'shipping';
            const trackingUrl = `https://tracking.packeta.com/cs/?id=${trackingNumber}`;
            contentHtml = `
                <h2 style="color:${COLORS.primary};margin:0 0 16px 0;font-size:24px;font-weight:bold">Tvůj BoostUp je na cestě! 🚀</h2>
                <p style="margin:0 0 24px 0;font-size:16px;color:${COLORS.secondary}">Tvůj balíček k objednávce <strong>${orderNumber}</strong> jsme právě předali Zásilkovně.</p>
                <div style="background:#f9fafb;padding:32px;border-radius:24px;margin:24px 0;border:1px solid #f3f4f6;text-align:center">
                    <p style="margin:0 0 8px 0;font-size:12px;color:${COLORS.secondary};text-transform:uppercase;font-weight:bold;letter-spacing:1px">Sledovací číslo</p>
                    <p style="font-size:24px;font-weight:bold;margin:0 0 20px 0;color:${COLORS.primary}">${trackingNumber}</p>
                    <a href="${trackingUrl}" style="background:${COLORS.primary};color:white;padding:14px 28px;border-radius:12px;text-decoration:none;font-weight:bold;display:inline-block;font-size:16px">Sledovat zásilku</a>
                </div>
            `;
            break;
        }

        case 'contact_auto_reply':
            subject = 'Díky za tvou zprávu! | BoostUp';
            contentHtml = `
                <h2 style="color:${COLORS.primary};margin:0 0 16px 0;font-size:24px;font-weight:bold">Zpráva přijata ⚡</h2>
                <p style="margin:0 0 24px 0;font-size:16px;color:${COLORS.secondary}">Ahoj, tvoje zpráva dorazila k nám do BoostUpu. Ozveme se ti co nejdříve, obvykle to netrvá déle než pár hodin.</p>
                <div style="background:#f9fafb;padding:24px;border-radius:16px;margin:24px 0;border:1px solid #f3f4f6;font-style:italic;color:${COLORS.secondary};text-align:left">
                    "${message}"
                </div>
                <p style="margin:0;font-size:14px;color:${COLORS.secondary}">Zatím můžeš mrknout na naše novinky na <a href="https://instagram.com/drinkboostup" style="color:${COLORS.primary};font-weight:600;text-decoration:none">Instagramu</a>.</p>
            `;
            break;

        case 'newsletter_signup':
            subject = 'Nový odběratel newsletteru! 📧';
            contentHtml = `
                <h2 style="color:${COLORS.primary};margin:0 0 16px 0;font-size:24px;font-weight:bold">Nový zájemce o BoostUp</h2>
                <p style="margin:0 0 24px 0;font-size:16px;color:${COLORS.secondary}">Máme nového odběratele v newsletteru.</p>
                <div style="background:#f9fafb;padding:24px;border-radius:16px;margin:24px 0;border:1px solid #f3f4f6;text-align:center">
                    <p style="margin:0 0 8px 0;font-size:12px;color:${COLORS.secondary};text-transform:uppercase;font-weight:bold">E-mail</p>
                    <p style="font-size:20px;font-weight:bold;margin:0;color:${COLORS.primary}">${req.body.subscriberEmail}</p>
                </div>
            `;
            break;

        case 'contact_inquiry':
            subject = 'Nová zpráva z kontaktního formuláře 📩';
            contentHtml = `
                <h2 style="color:${COLORS.primary};margin:0 0 16px 0;font-size:24px;font-weight:bold">Nová zpráva od zákazníka</h2>
                <div style="background:#f9fafb;padding:24px;border-radius:16px;margin:24px 0;border:1px solid #f3f4f6;text-align:left">
                    <p style="margin:0 0 16px 0;font-size:14px;color:${COLORS.secondary}">
                        <strong>Od:</strong> ${customerName} (${req.body.customerEmail})
                    </p>
                    <p style="margin:0;color:${COLORS.text};line-height:1.6">
                        ${message}
                    </p>
                </div>
            `;
            
            // Store inquiry in the messages table
            try {
                await supabaseAdmin.from('messages').insert({
                    from_email: req.body.customerEmail,
                    from_name: customerName,
                    subject: subject,
                    body_text: message,
                    body_html: contentHtml,
                    is_read: false
                });
            } catch (err) {
                console.error('Failed to store message inquiry:', err);
            }
            break;
    }

    const emailHtml = `
        <!DOCTYPE html>
        <html>
        <head>
            <meta charset="utf-8">
            <meta name="viewport" content="width=device-width, initial-scale=1.0">
            <title>${subject}</title>
        </head>
        <body style="margin:0;padding:0;background-color:#f8f9fa;font-family:-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif;color:${COLORS.text}">
            <table width="100%" border="0" cellspacing="0" cellpadding="0">
                <tr>
                    <td align="center" style="padding:40px 20px">
                        <table width="600" border="0" cellspacing="0" cellpadding="0" style="background-color:white;border-radius:32px;overflow:hidden;box-shadow:0 10px 30px rgba(0,0,0,0.03)">
                            <!-- Header / Logo -->
                            <tr>
                                <td align="center" style="padding:48px 40px 24px 40px;">
                                    <img src="cid:logo" alt="BoostUp" width="200" border="0" style="display:block;height:auto;border:none;outline:none;text-decoration:none">
                                </td>
                            </tr>
                            
                            ${heroImageUrl ? `
                            <tr>
                                <td align="center" style="padding: 0 40px;">
                                    <img src="cid:hero" alt="" width="520" border="0" style="width:520px;max-width:100%;height:auto;display:block;border:none;outline:none;text-decoration:none;border-radius:16px;">
                                </td>
                            </tr>
                            ` : ''}

                            <!-- Body Content -->
                            <tr>
                                <td align="center" style="padding:32px 40px 48px 40px;line-height:1.6;font-size:16px;text-align:center;">
                                    <div style="color:${COLORS.text};">
                                        ${contentHtml}
                                    </div>
                                </td>
                            </tr>
                        </table>
                        
                        <!-- Footer outside the card -->
                        <table width="600" border="0" cellspacing="0" cellpadding="0">
                            <tr>
                                <td align="center" style="padding:32px 40px;font-size:13px;color:${COLORS.secondary}">
                                    <p style="margin:0 0 8px 0;font-weight:500">BoostUp &middot; Chaloupkova 3002/1a &middot; 612 00 Brno</p>
                                    <p style="margin:0">
                                        <a href="${BASE_URL}" style="color:${COLORS.primary};text-decoration:none;font-weight:700">${BASE_URL.replace('https://', '')}</a>
                                        &nbsp;&nbsp;&middot;&nbsp;&nbsp;
                                        <a href="mailto:info@drinkboostup.cz" style="color:${COLORS.primary};text-decoration:none;font-weight:500">info@drinkboostup.cz</a>
                                    </p>
                                </td>
                            </tr>
                        </table>
                    </td>
                </tr>
            </table>
        </body>
        </html>
    `;

    try {
        const attachments: any[] = [
            {
                content: LOGO_BASE64,
                filename: 'logo.png',
                contentId: 'logo',
                disposition: 'inline'
            }
        ];

        if (heroImageUrl) {
            try {
                const imageName = heroImageUrl.split('/').pop()?.split('?')[0];
                if (imageName) {
                    const heroPath = path.join(process.cwd(), 'public', imageName);
                    if (fs.existsSync(heroPath)) {
                        const heroContent = fs.readFileSync(heroPath).toString('base64');
                        attachments.push({
                            content: heroContent,
                            filename: `${heroCid}.png`,
                            contentId: 'hero',
                            disposition: 'inline'
                        });
                    }
                }
            } catch (e) {
                console.error('Failed to read hero image file:', e);
            }
        }

        let bccRecipient = undefined;
        if (type === 'order_confirmation') {
            bccRecipient = ADMIN_EMAIL;
        } else if (['contact_inquiry', 'newsletter_signup'].includes(type)) {
            bccRecipient = INFO_EMAIL;
        }

        const { data, error } = await resend.emails.send({
            from: 'BoostUp <objednavky@drinkboostup.cz>',
            to: [to],
            bcc: bccRecipient ? [bccRecipient] : undefined,
            subject: subject,
            html: emailHtml,
            attachments: attachments
        });

        if (error) {
            console.error('Resend SDK error:', error);
            return res.status(500).json({ error });
        }

        return res.status(200).json({ success: true, id: data?.id });
    } catch (err) {
        console.error('Email send error:', err);
        return res.status(500).json({ error: 'Failed to send email' });
    }
}
